    private void setupModeUI() {
        if (isDemoMode) {
            jToggleButton1.setVisible(false);
            jButton2.setVisible(true);
            jButton1.setVisible(true);

            jScrollPane1.setVisible(false);   // Visa stora rutan 
            jScrollPane5.setVisible(true);  // Göm "UT"-rutan 
            jScrollPane6.setVisible(true);  // Göm "IN"-rutan 

            txtSent.setText("Utgående kommandon: \n");
            txtReceived.setText("Inkommande kommandon: \n");

            appendStatus("Demoläge aktiverat: Beräknar första rutten... \n");

            unvisitedMissions.clear();
            for (int i = 1; i < ds.locations; i++) {
                unvisitedMissions.add(i);
            }

            planNextMission();

            jButton3.setEnabled(true);
            jButton4.setEnabled(true);
            jButton5.setEnabled(true);

        } else {
            jToggleButton1.setVisible(false);
            jButton3.setVisible(false);
            jButton4.setVisible(false);
            jButton5.setVisible(false);

            prepareRealModeLog();
        }
    }

    private void prepareRealModeLog() {
        jScrollPane1.setVisible(false);
        jScrollPane5.setVisible(true);
        jScrollPane6.setVisible(true);

        txtSent.setText("Utgående kommandon: \n"); // Lägg till körriktning osv. 
        txtReceived.setText("Inkommande data: \n"); // + position, status, hinder, 
    }

    public void showStatus() {
        System.out.println("Start at: " + ds.LocationX[0] + ", " + ds.LocationY[0]);
    }

    private boolean planNextMission() {
        if (unvisitedMissions.isEmpty()) {
            appendStatus("Alla uppdrag klara!\n");
            return false;
        }

        // --- Paus vid hemstationen inför varje NY rutt (endast fysisk AGV) ---
        if (!isDemoMode && !ds.isLoaded) {
            appendStatus("Förbereder nästa hämtning... Väntar 5 sekunder vid basen.\n");
            try {
                Thread.sleep(5000);
            } catch (InterruptedException e) {
            }
        }

        int bestIndex = -1;
        double shortestDistance = Double.MAX_VALUE;
        java.util.List<Vertex> bestPath = null;

        int currentX = (int) (ds.robotX / ds.gridsize);
        int currentY = (int) (ds.robotY / ds.gridsize);
        int startNodeId = (currentY * ds.columns) + currentX;

        // Hitta närmaste uppdrag
        for (int i : unvisitedMissions) {
            int destX = (int) (ds.LocationX[i] / ds.gridsize);
            int destY = (int) (ds.LocationY[i] / ds.gridsize);
            int destNodeId = (destY * ds.columns) + destX;

            op.createPlan(startNodeId, destNodeId);
            if (ds.currentPath != null && !ds.currentPath.isEmpty()) {

                double dist = ds.currentPath.size();

                if (dist < shortestDistance) {
                    shortestDistance = dist;
                    bestIndex = i;
                    bestPath = new java.util.ArrayList<>(ds.currentPath);
                }
            }
        }

    if (bestIndex != -1 && bestPath != null) {
            unvisitedMissions.remove(Integer.valueOf(bestIndex));
            ds.currentPath = bestPath;
            currentMissionIndex = bestIndex; 

            appendStatus("Ny rutt planerad till parkering: " + bestIndex + "\n");

            KinematicsTransformer transformer = new KinematicsTransformer(ds);
            
            // --- FIX 1: Nollställ AGV:n inför nästa utresa! ---
            // Istället för att fortsätta där den gamla hemresan slutade (vänd bakåt),
            // tvingar vi den att stå på Hemstationen, vänd framåt (0.0) och vara lastad (true)
            double homeX = ds.LocationX[0];
            double homeY = ds.LocationY[0];
            double homeAxleX = homeX - (ds.agvOffset * ds.gridsize);
            RobotState startState = new RobotState(homeX, homeY, homeAxleX, homeY, 0.0, true);
            // ----------------------------------------------------

            java.util.List<Vertex> outPath = new java.util.ArrayList<>(bestPath);
            if (!outPath.isEmpty()) {
                outPath.remove(0);
            }

            // Förvandla utresan visuellt
            java.util.List<RobotState> detailedOut = transformer.transformPath(outPath, true, startState);

            int destX = (int) (ds.LocationX[bestIndex] / ds.gridsize);
            int destY = (int) (ds.LocationY[bestIndex] / ds.gridsize);

            // Lägg till den visuella parkeringen (ritar blå linje i GUI)
            if (bestIndex >= 5 && bestIndex <= 9) {
                appendStatus("Utför parkering: Cirkelbåge och backning \n");
                RobotState lastState = detailedOut.get(detailedOut.size() - 1);
                java.util.List<RobotState> maneuver = transformer.generateParkingManeuver(lastState, destX, destY);
                detailedOut.addAll(maneuver);
            } else if (bestIndex == 1) {
                appendStatus("Utför parkering: U-sväng och backning vänster \n");
                RobotState lastState = detailedOut.get(detailedOut.size() - 1);
                java.util.List<RobotState> maneuver = transformer.generateComplexParkingManeuver(lastState, destX, destY);
                detailedOut.addAll(maneuver);
            } else if (bestIndex >= 2 && bestIndex <= 4) {
                appendStatus("Utför parkering: U-sväng och backning höger \n");
                RobotState lastState = detailedOut.get(detailedOut.size() - 1);
                java.util.List<RobotState> maneuver = transformer.generateTopParkingManeuver(lastState, destX, destY);
                detailedOut.addAll(maneuver);
            } else if (bestIndex == 10) {
                appendStatus("Utför parkering: backning vid hörn \n");
                RobotState lastState = detailedOut.get(detailedOut.size() - 1);
                java.util.List<RobotState> maneuver = transformer.generateSpot10Maneuver(lastState);
                detailedOut.addAll(maneuver);
            }

            // --- SPARA TILL DEMON OCH GUI ---
            masterDemoPath.addAll(detailedOut);
            masterDemoRedSpots.add(new java.awt.geom.Point2D.Double(ds.LocationX[bestIndex], ds.LocationY[bestIndex]));
            masterDemoStops.add(masterDemoPath.size() - 1);
            
            // --- FIX 2a: Spara UTRESANS blå linje ---
            currentOutboundLine = new java.util.ArrayList<>(ds.robotTrajectory);

            // =================================================================
            // VÄGKORSNING: DRIFT ELLER DEMO?
            // =================================================================
            if (!isDemoMode) {
                // --- 1. DRIFTLÄGE (FYSISK AGV) ---

                RouteOptimizer optimizer = new RouteOptimizer(ds);
                optimizer.compressPath(outPath, true);

                RobotState lastState = detailedOut.get(detailedOut.size() - 1);

                if (bestIndex >= 5 && bestIndex <= 9) {
                    ds.instructionQueue.add(new AgvInstruction(InstructionsStore.MOVE_LEFT, 100, 0, destX, destY, true));
                    ds.instructionQueue.add(new AgvInstruction(InstructionsStore.MOVE_DOWN, 100, 0, destX, destY, true));

                    ds.instructionQueue.add(new AgvInstruction('X'));
                    ds.instructionQueue.add(new AgvInstruction('W', 5000));

                    java.awt.geom.Point2D freePos = calculateFreeingTarget(destX, destY, lastState.angle, 75.0);
                    ds.instructionQueue.add(new AgvInstruction(InstructionsStore.MOVE_UP, 100, 75, (int) freePos.getX(), (int) freePos.getY(), true));
                } else if (bestIndex == 1) {
                    ds.instructionQueue.add(new AgvInstruction(InstructionsStore.MOVE_LEFT, 100, 0, destX, destY, true));
                    ds.instructionQueue.add(new AgvInstruction(InstructionsStore.MOVE_DOWN, 100, 0, destX, destY, true));
                    ds.instructionQueue.add(new AgvInstruction(InstructionsStore.MOVE_RIGHT, 100, 0, destX, destY, true));

                    ds.instructionQueue.add(new AgvInstruction('X'));
                    ds.instructionQueue.add(new AgvInstruction('W', 5000));

                    java.awt.geom.Point2D freePos = calculateFreeingTarget(destX, destY, lastState.angle, 30.0);
                    ds.instructionQueue.add(new AgvInstruction(InstructionsStore.MOVE_UP, 100, 30, (int) freePos.getX(), (int) freePos.getY(), false));
                    ds.instructionQueue.add(new AgvInstruction(InstructionsStore.MOVE_LEFT, 100, 40, (int) freePos.getX(), (int) freePos.getY(), true));
                } else if (bestIndex >= 2 && bestIndex <= 4) {
                    ds.instructionQueue.add(new AgvInstruction(InstructionsStore.MOVE_RIGHT, 100, 0, destX, destY, true));
                    ds.instructionQueue.add(new AgvInstruction(InstructionsStore.MOVE_DOWN, 100, 0, destX, destY, true));
                    ds.instructionQueue.add(new AgvInstruction(InstructionsStore.MOVE_LEFT, 100, 0, destX, destY, true));

                    ds.instructionQueue.add(new AgvInstruction('X'));
                    ds.instructionQueue.add(new AgvInstruction('W', 5000));

                    java.awt.geom.Point2D freePos = calculateFreeingTarget(destX, destY, lastState.angle, 20.0);
                    ds.instructionQueue.add(new AgvInstruction(InstructionsStore.MOVE_UP, 100, 20, (int) freePos.getX(), (int) freePos.getY(), false));
                    ds.instructionQueue.add(new AgvInstruction(InstructionsStore.MOVE_RIGHT, 100, 40, (int) freePos.getX(), (int) freePos.getY(), true));
                } else if (bestIndex == 10) {
                    ds.instructionQueue.add(new AgvInstruction(InstructionsStore.MOVE_LEFT, 100, 0, destX, destY, true));
                    ds.instructionQueue.add(new AgvInstruction(InstructionsStore.MOVE_DOWN, 100, 0, destX, destY, true));
                    ds.instructionQueue.add(new AgvInstruction(InstructionsStore.MOVE_RIGHT, 100, 0, destX, destY, true));
                    ds.instructionQueue.add(new AgvInstruction(InstructionsStore.MOVE_DOWN, 100, 0, destX, destY, true));

                    ds.instructionQueue.add(new AgvInstruction('X'));
                    ds.instructionQueue.add(new AgvInstruction('W', 5000));

                    java.awt.geom.Point2D freePos = calculateFreeingTarget(destX, destY, lastState.angle, 75.0);
                    ds.instructionQueue.add(new AgvInstruction(InstructionsStore.MOVE_UP, 100, 75, (int) freePos.getX(), (int) freePos.getY(), true));
                }

                // AVBRYT HÄR FÖR DEN FYSISKA AGV:N! Hemresan beräknas senare.
                ds.waitingForReturn = true;
                return true;
            }
        }
        return false;
    }
    

    public void recalculateCurrentMission() {
        if (currentMissionIndex == -1) {
            return;
        }
        appendStatus("Räknar om rutten från nuvarande position...\n");

        int currentX = (int) (ds.robotX / ds.gridsize);
        int currentY = (int) (ds.robotY / ds.gridsize);
        int startNodeId = (currentY * ds.columns) + currentX;

        int destX = (int) (ds.LocationX[currentMissionIndex] / ds.gridsize);
        int destY = (int) (ds.LocationY[currentMissionIndex] / ds.gridsize);
        int endNodeId = (destY * ds.columns) + destX;

        // Skapa en ny rutt i grafen
        op.createPlan(startNodeId, endNodeId);

        if (ds.currentPath != null && !ds.currentPath.isEmpty()) {
            RouteOptimizer optimizer = new RouteOptimizer(ds);
            optimizer.compressPath(ds.currentPath, ds.isLoaded);

            ds.isPaused = false;
            repaint();
        } else {
            appendStatus("FEL: Kunde inte hitta någon ny väg till målet!\n");
        }
    }

