    private void jButton1ActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_jButton1ActionPerformed
        // 1. Pausa tråden!
        ds.isPaused = true;
        appendStatus("AGVn är pausad...\n");

        if (btTransceiver != null) {
            btTransceiver.skickaStoppKommando();
        }

        // Knappar till popup-ruta
        Object[] options = {"Ja", "Nej"};

        // 2. Visa popup-rutan (JOptionPane)
        int response = javax.swing.JOptionPane.showOptionDialog(
                ControlUI.this,
                "Körningen pausades, fortsätt?",
                "Paus",
                javax.swing.JOptionPane.YES_NO_OPTION,
                javax.swing.JOptionPane.QUESTION_MESSAGE,
                null,
                options,
                options[0] //Förvald knapp
        );

        // 3. Hantera användarens svar
        if (response == javax.swing.JOptionPane.YES_OPTION) {
            // Användaren klickade "Ja"
            appendStatus("Återupptar körningen...\n");
            ds.isPaused = false; // Släpp pausen!
        } else { // Avsluta samtliga processer om användaren väljer "Nej"           
            System.out.println("Avslutar programmet...");
            System.exit(0);
        }
    }//GEN-LAST:event_jButton1ActionPerformed

