public java.awt.geom.Point2D calculateFreeingTarget(int destX, int destY, double angle, double dist_cm) {
        double targetX_cm = (destX * ds.gridsize + ds.gridsize / 2.0) + dist_cm * Math.cos(angle);
        double targetY_cm = (destY * ds.gridsize + ds.gridsize / 2.0) + dist_cm * Math.sin(angle);
        return new java.awt.geom.Point2D.Double(targetX_cm / ds.gridsize, targetY_cm / ds.gridsize);
    }

    public void planDynamicReturnTrip() {
        appendStatus("Frigörelse klar. Beräknar hemresa från faktisk position...\n");

        int currentX = (int) (ds.robotX / ds.gridsize);
        int currentY = (int) (ds.robotY / ds.gridsize);
        int startNodeId = (currentY * ds.columns) + currentX;

        int homeX = (int) (ds.LocationX[0] / ds.gridsize);
        int homeY = (int) (ds.LocationY[0] / ds.gridsize);
        int homeNodeId = (homeY * ds.columns) + homeX;

        op.createReturnPlan(startNodeId, homeNodeId);

        repaint();
    }

